import{_ as e,o as n,c as o,ae as a}from"./chunks/framework.CyZiF_rV.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"en/srodowiska.md","filePath":"en/srodowiska.md"}'),r={name:"en/srodowiska.md"};function i(s,t,d,c,l,m){return n(),o("div",null,[...t[0]||(t[0]=[a('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/srodowiska.md" target="_blank" rel="noreferrer">srodowiska.md</a></p></blockquote><h2 id="ksef-api-2-0-environments" tabindex="-1">KSeF API 2.0 Environments <a class="header-anchor" href="#ksef-api-2-0-environments" aria-label="Permalink to &quot;KSeF API 2.0 Environments&quot;">​</a></h2><p>15.12.2025</p><p>Below is a summary of the public environments.</p><table tabindex="0"><thead><tr><th>Abbr.</th><th>Environment</th><th>Description</th><th>API Documentation</th><th>Allowed Formats</th></tr></thead><tbody><tr><td><strong>TEST</strong></td><td>Test <br> (Release Candidate)</td><td>Environment for testing integration with KSeF API 2.0, contains RC versions.</td><td><a href="https://api-test.ksef.mf.gov.pl/docs/v2" target="_blank" rel="noreferrer">https://api-test.ksef.mf.gov.pl/docs/v2</a></td><td>FA(2), FA(3), FA_PEF (3), FA_KOR_PEF (3)</td></tr><tr><td><strong>DEMO</strong></td><td>Pre-production (Demo)</td><td>Environment matching the production configuration, intended for final integration validation under conditions close to production.</td><td><a href="https://api-demo.ksef.mf.gov.pl/docs/v2" target="_blank" rel="noreferrer">https://api-demo.ksef.mf.gov.pl/docs/v2</a></td><td>FA(3), FA_PEF (3), FA_KOR_PEF (3)</td></tr><tr><td><strong>PRD</strong></td><td>Production</td><td>Environment for issuing and receiving invoices with full legal force, with guaranteed SLA and actual production data.</td><td><a href="https://api.ksef.mf.gov.pl/docs/v2" target="_blank" rel="noreferrer">https://api.ksef.mf.gov.pl/docs/v2</a></td><td>FA(3), FA_PEF (3), FA_KOR_PEF (3)</td></tr></tbody></table><blockquote><p>&lt;font color=&quot;red&quot;&gt;Warning:&lt;/font&gt; Test environments (TE/DEMO) are intended solely for testing integration with the KSeF API. Do not submit <strong>production invoices</strong> or real entity data to them.</p></blockquote><p>In the test environment <code>TE</code>, authentication using self-signed certificates is permitted, which in practice means that many integrators can <a href="./uwierzytelnianie.html#proces-uwierzytelniania">authenticate</a> in the context of the same company. For this reason, data entered in the <code>TE</code> environment is not isolated and may be shared between integrators. Use random NIP identifiers for testing, avoiding any real data.</p><h3 id="maintenance-work-on-test-environments" tabindex="-1">Maintenance Work on Test Environments <a class="header-anchor" href="#maintenance-work-on-test-environments" aria-label="Permalink to &quot;Maintenance Work on Test Environments&quot;">​</a></h3><p>Due to the planned, systematic development of the National e-Invoice System (KSeF 2.0), <strong>from October 1, 2025</strong>, periodic maintenance work may be carried out on the System&#39;s test environments.</p><p>This work will take place between <strong>4:00 PM and 6:00 PM</strong>. During this time, temporary difficulties accessing the test environments may occur.</p><p>After maintenance is completed, only <strong>changes affecting integration</strong> will be published in the <a href="./api-changelog.html">changelog</a> — for example, changes in API behavior, contract modifications, XSD schema changes, limits, etc. Changes that do not affect the API and are invisible from an integration perspective — such as internal quality, performance, or security fixes — <strong>may not be communicated</strong> or will be presented in summary form.</p>',11)])])}const f=e(r,[["render",i]]);export{p as __pageData,f as default};
